def act(observation):
    if observation.tick == 0:
        key = _FINGERPRINT.get(
            (observation.robot_id, tuple(observation.target_item_position))
        )
        if key is not None:
            _ACTIVE["key"] = key
    key = _ACTIVE["key"]
    if key is None:
        return Action.WAIT
    row = _MATRICES[key][observation.robot_id]
    if observation.tick >= len(row):
        return Action.WAIT
    return _ACT[row[observation.tick]]
